    'wizard.palette.text2':             { fr: "pour tout faire au clavier : insérer un modèle, ouvrir une IA, changer de thème, lancer une commande.", en: 'to do everything from the keyboard: insert a template, open an AI, switch theme, run a command.', es: 'para hacer todo desde el teclado: insertar plantilla, abrir IA, cambiar tema, ejecutar comando.', de: 'um alles per Tastatur zu erledigen: Vorlage einfügen, KI öffnen, Theme wechseln, Befehl ausführen.', it: 'per fare tutto da tastiera: inserire modello, aprire IA, cambiare tema, eseguire comando.', pt: 'para fazer tudo pelo teclado: inserir modelo, abrir IA, mudar tema, executar comando.', nl: 'om alles via toetsenbord te doen: sjabloon invoegen, AI openen, thema wisselen, commando uitvoeren.' },
