    'wizard.palette.cmd':               { fr: 'Commandes : sauvegarder, copier, changer le thème, ouvrir les réglages, rechercher…', en: 'Commands: save, copy, switch theme, open settings, search…', es: 'Comandos: guardar, copiar, cambiar tema, abrir ajustes, buscar…', de: 'Befehle: speichern, kopieren, Theme wechseln, Einstellungen, suchen…', it: 'Comandi: salva, copia, cambia tema, apri impostazioni, cerca…', pt: 'Comandos: salvar, copiar, mudar tema, abrir ajustes, buscar…', nl: 'Commando\'s: opslaan, kopiëren, thema wisselen, instellingen, zoeken…' },
