    'wizard.theme.text':                { fr: 'Sombre, clair ou auto (suit votre OS). Modifiable plus tard dans Réglages › Affichage.', en: 'Dark, light, or auto (follows your OS). Can be changed later in Settings › Display.', es: 'Oscuro, claro o auto (sigue su SO). Modificable más tarde en Ajustes › Visualización.', de: 'Dunkel, hell oder Auto (folgt dem OS). Später änderbar unter Einstellungen › Anzeige.', it: 'Scuro, chiaro o auto (segue il tuo OS). Modificabile in seguito in Impostazioni › Visualizzazione.', pt: 'Escuro, claro ou auto (segue seu SO). Alterável depois em Configurações › Exibição.', nl: 'Donker, licht of auto (volgt uw OS). Later aanpasbaar in Instellingen › Weergave.' },
    'wizard.templates.title':           { fr: 'Modèles de prompts',                                     en: 'Prompt templates',                                  es: 'Plantillas de prompts',                            de: 'Prompt-Vorlagen',                                  it: 'Modelli di prompt',                                pt: 'Modelos de prompts',                               nl: 'Prompt-sjablonen' },
    'wizard.templates.text':            { fr: 'Cliquez sur le bouton 📝 « Modèles » pour enregistrer une saisie comme modèle réutilisable. Idéal pour les prompts récurrents (review, refacto, debug…).', en: 'Click the 📝 "Templates" button to save an entry as a reusable template. Ideal for recurring prompts (review, refactor, debug…).', es: 'Haz clic en el botón 📝 «Plantillas» para guardar una entrada como plantilla reutilizable. Ideal para prompts recurrentes (revisión, refactorización, depuración…).', de: 'Klicke auf 📝 „Vorlagen", um eine Eingabe als wiederverwendbare Vorlage zu speichern. Ideal für wiederkehrende Prompts (Review, Refactor, Debug…).', it: 'Fai clic sul pulsante 📝 "Modelli" per salvare un\'inserzione come modello riutilizzabile. Ideale per prompt ricorrenti (review, refactor, debug…).', pt: 'Clique no botão 📝 "Modelos" para salvar uma entrada como modelo reutilizável. Ideal para prompts recorrentes (revisão, refatoração, depuração…).', nl: 'Klik op de knop 📝 "Sjablonen" om een invoer op te slaan als herbruikbaar sjabloon. Ideaal voor terugkerende prompts (review, refactor, debug…).' },
    'wizard.templates.tip1':            { fr: 'Cliquez « Modèles » → « Enregistrer la saisie » pour capturer le prompt actuel.', en: 'Click "Templates" → "Save entry" to capture the current prompt.', es: 'Haz clic en «Plantillas» → «Guardar entrada» para capturar el prompt actual.', de: 'Klicke auf „Vorlagen" → „Eingabe speichern", um den aktuellen Prompt zu erfassen.', it: 'Fai clic su "Modelli" → "Salva inserimento" per catturare il prompt attuale.', pt: 'Clique em "Modelos" → "Salvar entrada" para capturar o prompt atual.', nl: 'Klik op "Sjablonen" → "Invoer opslaan" om de huidige prompt vast te leggen.' },
    'wizard.templates.tip2':            { fr: 'Cliquez sur un modèle pour l\'insérer dans la zone de saisie.', en: 'Click a template to insert it into the editor.',     es: 'Haz clic en una plantilla para insertarla en el editor.', de: 'Klicke auf eine Vorlage, um sie in den Editor einzufügen.', it: 'Fai clic su un modello per inserirlo nell\'editor.', pt: 'Clique em um modelo para inseri-lo no editor.',    nl: 'Klik op een sjabloon om het in de editor in te voegen.' },
    'wizard.templates.tip3':            { fr: 'Les modèles sont sauvegardés et exportés avec votre configuration.', en: 'Templates are saved and exported with your configuration.', es: 'Las plantillas se guardan y exportan con tu configuración.', de: 'Vorlagen werden mit deiner Konfiguration gespeichert und exportiert.', it: 'I modelli sono salvati ed esportati con la tua configurazione.', pt: 'Os modelos são salvos e exportados com sua configuração.', nl: 'Sjablonen worden opgeslagen en geëxporteerd met uw configuratie.' },
    'wizard.privacy.title':             { fr: 'Confidentialité par défaut',                             en: 'Privacy by default',                                es: 'Privacidad por defecto',                           de: 'Datenschutz standardmäßig',                        it: 'Privacy predefinita',                              pt: 'Privacidade por padrão',                           nl: 'Privacy standaard' },
    'wizard.privacy.text':              { fr: 'My-Feedbacks masque automatiquement les données sensibles avant qu\'elles soient stockées : emails, IBAN, cartes bancaires (Luhn), JWT, tokens Bearer/sk-/ghp_.', en: 'My-Feedbacks automatically masks sensitive data before it\'s stored: emails, IBANs, credit cards (Luhn), JWTs, Bearer/sk-/ghp_ tokens.', es: 'My-Feedbacks enmascara automáticamente los datos sensibles antes de almacenarlos: emails, IBANs, tarjetas (Luhn), JWTs, tokens Bearer/sk-/ghp_.', de: 'My-Feedbacks maskiert sensible Daten automatisch vor der Speicherung: E-Mails, IBANs, Kreditkarten (Luhn), JWTs, Bearer/sk-/ghp_-Tokens.', it: 'My-Feedbacks maschera automaticamente i dati sensibili prima dell\'archiviazione: email, IBAN, carte (Luhn), JWT, token Bearer/sk-/ghp_.', pt: 'My-Feedbacks mascara automaticamente dados sensíveis antes do armazenamento: emails, IBANs, cartões (Luhn), JWTs, tokens Bearer/sk-/ghp_.', nl: 'My-Feedbacks maskeert gevoelige gegevens automatisch voor opslag: e-mails, IBAN\'s, creditcards (Luhn), JWT\'s, Bearer/sk-/ghp_-tokens.' },
    'wizard.privacy.local':             { fr: 'Tout reste local — aucune télémétrie, aucun envoi serveur. Voir le détail dans Réglages › Confidentialité.', en: 'Everything stays local — no telemetry, no server traffic. See details in Settings › Privacy.', es: 'Todo permanece local — sin telemetría, sin envío al servidor. Ver detalles en Ajustes › Privacidad.', de: 'Alles bleibt lokal — keine Telemetrie, kein Server-Versand. Details unter Einstellungen › Datenschutz.', it: 'Tutto rimane locale — nessuna telemetria, nessun invio al server. Dettagli in Impostazioni › Privacy.', pt: 'Tudo permanece local — sem telemetria, sem envio para servidor. Detalhes em Configurações › Privacidade.', nl: 'Alles blijft lokaal — geen telemetrie, geen serververkeer. Details in Instellingen › Privacy.' },
